            NewLoomEdge {
                edge_id: None,
                workspace_id: workspace.id.clone(),
                source_block_id: file_block.block_id.clone(),
                target_block_id: tag_hub.block_id.clone(),
                edge_type: LoomEdgeType::Tag,
