                ..Default::default()
            },
            50,
            0,
        )
        .await?;
    let LoomViewResponse::All { blocks } = all_notes else {
        panic!("expected all view response");
    };
    assert_eq!(
        loom_block_ids(&blocks),
        sorted_strings(vec![
            portable_note.block_id.clone(),
            unlinked_note.block_id.clone(),
            mention_target.block_id.clone(),
