    let future_notes = db
        .query_loom_view(
            &workspace.id,
            LoomViewType::All,
            LoomViewFilters {
                date_from: Some(Utc::now() + Duration::days(1)),
                ..Default::default()
            },
            50,
            0,
        )
        .await?;
    let LoomViewResponse::All {
        blocks: future_blocks,
    } = future_notes
    else {
        panic!("expected all view response");
    };
    assert!(future_blocks.is_empty());

    let pinned = db
        .query_loom_view(
            &workspace.id,
            LoomViewType::Pins,
            LoomViewFilters::default(),
            50,
            0,
