        panic!("expected pins view response");
    };
    assert_eq!(
        loom_block_ids(&blocks),
        vec![portable_note.block_id.clone()]
    );

    let tagged_notes = db
        .query_loom_view(
            &workspace.id,
            LoomViewType::All,
            LoomViewFilters {
                content_type: Some(LoomBlockContentType::Note),
                tag_ids: vec![tag_hub.block_id.clone()],
                ..Default::default()
            },
            50,
            0,
